public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Build a realistic-sized input: ~10 000 words from a repeating phrase.
        const string phrase = "the quick brown fox jumps over the lazy dog and the cat sat on the mat ";
        var sb = new System.Text.StringBuilder(phrase.Length * 700);
        for (int i = 0; i < 700; i++)
            sb.Append(phrase);
        _analyzer = new TextAnalyzer(sb.ToString());
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

